import{_ as s,d as n,e as d,f as e,g as i,w as r,i as t,t as l,k as p,s as u}from"./index-CCDlRpOG.js";const c={class:"legal"},f={class:"page-top"},h={class:"muted footer-links"},b="July 14, 2026",v={__name:"PrivacyPage",setup(m){return(y,a)=>{const o=u("router-link");return n(),d("div",c,[e("div",f,[i(o,{to:"/",class:"home-link"},{default:r(()=>[...a[0]||(a[0]=[t("‹ Home",-1)])]),_:1})]),a[4]||(a[4]=e("h1",null,"Privacy policy",-1)),e("p",{class:"muted updated"},"Last updated "+l(b)),a[5]||(a[5]=p('<p data-v-ba0f1338> SaunaSpeak is a web app for learning spoken Finnish, operated as an independent product from Finland&#39;s neighborhood (EU). This page explains what we store, why, and what you can do about it - in plain language, because nobody learns Finnish to read legalese. </p><h2 data-v-ba0f1338>What we store</h2><ul data-v-ba0f1338><li data-v-ba0f1338><b data-v-ba0f1338>Account:</b> your name, email address and a hashed password (we can never read the password itself).</li><li data-v-ba0f1338><b data-v-ba0f1338>Learning data:</b> which sentences and words you&#39;ve studied, your self-grades, review schedule, streak, XP, checkpoints, preferences (goal, daily time, audio speed), timezone, and a few one-time product milestones such as opening or completing the free guided Situation. This is the product - spaced repetition and the learning journey can&#39;t work without it.</li><li data-v-ba0f1338><b data-v-ba0f1338>Chat messages:</b> what you write to Väinö or a scenario character is sent to an AI provider to generate the reply (see below). Practice-attempt corrections are cached so identical mistakes get instant answers.</li><li data-v-ba0f1338><b data-v-ba0f1338>Billing (Löyly+ only):</b> payments run entirely through <a href="https://stripe.com/privacy" rel="noopener" target="_blank" data-v-ba0f1338>Stripe</a>. We store your Stripe customer and subscription IDs and your subscription status - never your card number.</li></ul><h2 data-v-ba0f1338>What we deliberately don&#39;t do</h2><ul data-v-ba0f1338><li data-v-ba0f1338>No advertising, no selling or sharing data with data brokers - ever.</li><li data-v-ba0f1338>No tracking cookies. Analytics run on <a href="https://umami.is/privacy" rel="noopener" target="_blank" data-v-ba0f1338>Umami</a>, a cookieless, EU-hosted service that counts page views without identifying you.</li><li data-v-ba0f1338>No social-media pixels, no fingerprinting.</li></ul><h2 data-v-ba0f1338>Processors we rely on</h2><p data-v-ba0f1338> A few services process data on our behalf, only to make features work: our hosting provider (servers and database), Stripe (payments), an email delivery provider (verification, password-reset and optional review-reminder mails), an AI provider (Anthropic, Google or OpenRouter - chat replies and practice corrections; messages are sent for processing, not used by us to train anything), and a speech-synthesis provider (Microsoft or Google) for generating Finnish audio. </p><h2 data-v-ba0f1338>Emails</h2><p data-v-ba0f1338> We send account emails (verification, password reset) and - if you keep the toggle on in your profile - a daily reminder when reviews are due. The reminder can be switched off in your profile at any time. </p><h2 data-v-ba0f1338>Your rights</h2><ul data-v-ba0f1338><li data-v-ba0f1338><b data-v-ba0f1338>Export:</b> download everything we hold about you as JSON from your profile (&quot;Download my data&quot;).</li><li data-v-ba0f1338><b data-v-ba0f1338>Deletion:</b> delete your account from your profile - it removes your account, progress, word bank and review history immediately, and cancels any active subscription. This is irreversible.</li><li data-v-ba0f1338><b data-v-ba0f1338>Correction &amp; access:</b> for anything else (GDPR articles 15-21), email us and we&#39;ll sort it out.</li></ul><h2 data-v-ba0f1338>Retention</h2><p data-v-ba0f1338> We keep your data for as long as your account exists. Delete the account and it&#39;s gone from the live database immediately; encrypted backups rotate out within 30 days. </p><h2 data-v-ba0f1338>Contact</h2><p data-v-ba0f1338> Questions, requests, complaints: <a href="mailto:mail@saunaspeak.com" data-v-ba0f1338>mail@saunaspeak.com</a>. You also have the right to lodge a complaint with your local data-protection authority. </p>',15)),e("p",h,[i(o,{to:"/terms"},{default:r(()=>[...a[1]||(a[1]=[t("Terms of service",-1)])]),_:1}),a[3]||(a[3]=t(" · ",-1)),i(o,{to:"/"},{default:r(()=>[...a[2]||(a[2]=[t("Home",-1)])]),_:1})])])}}},w=s(v,[["__scopeId","data-v-ba0f1338"]]);export{w as default};
